%%%%%%%%%% Function fTrexRoiInfV01.m %%%%%%%%%%% Function roi Figure Information, ver.1% Kei Nakamura% Created on Saturday, May 31st 2008.% Modified on %% function inf = fTrexRoiInfV01(dat);% returns an information string for a figure%function inf = fTrexRoiInfV01(dat,roiN);  %function headertl = ['r',num2str(roiN)];inf{1} = [tl,'Charge[pC]:',num2str(0.001*floor(1000*dat(1)))];inf{2} = [tl,'Energy[mJ]:',num2str(0.001*floor(1000*dat(2)))];inf{3} = [tl,'PeakE[MeV]:',num2str(dat(12))];inf{4} = [tl,'MeanE[MeV]:',num2str(dat(5))];inf{5} = [tl,'FWHM-Div[mrad]:',num2str(dat(10))];inf{6} = [tl,'RMS-Div[mrad]:',num2str(dat(3))];inf{7} = [tl,'FWHM-Rsl[%]:',num2str(dat(15))];inf{8} = [tl,'FWHM-Sprd[%]:',num2str(dat(16))];inf{9} = [tl,'RMS-Rsl[%]:',num2str(dat(8))];inf{10} = [tl,'RMS-Sprd[%]:',num2str(dat(9))];
